#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int data;
    struct Node* next;
} Node;

Node* detectCycle(Node* head) {
    if (!head || !head->next) return NULL;
    Node *slow = head, *fast = head;
    while (fast && fast->next) {
        slow = slow->next;
        fast = fast->next->next;
        if (slow == fast) {
            slow = head;
            while (slow != fast) {
                slow = slow->next;
                fast = fast->next;
            }
            return slow;
        }
    }
    return NULL;
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N; scanf("%d", &N);
        Node **nodes = (Node**)malloc(N * sizeof(Node*));
        Node *head = NULL, *cur = NULL;
        for (int i = 0; i < N; ++i) {
            int val; scanf("%d", &val);
            Node *nd = (Node*)malloc(sizeof(Node));
            nd->data = val; nd->next = NULL;
            if (!head) head = nd; else cur->next = nd;
            cur = nd;
            nodes[i] = nd;
        }
        int pos; scanf("%d", &pos);
        if (pos != -1) cur->next = nodes[pos];
        Node *start = detectCycle(head);
        if (start) printf("%d\n", start->data);
        else printf("NULL\n");
        free(nodes);
        // Note: not freeing the whole list because of possible cycles; judge process ends here.
    }
    return 0;
}

