const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
function nextLine() { return lines[idx++]; }

class Node {
    constructor(x) { this.data = x; this.next = null; }
}

function detectCycle(head) {
    if (!head || !head.next) return null;
    let slow = head, fast = head;
    while (fast && fast.next) {
        slow = slow.next;
        fast = fast.next.next;
        if (slow === fast) {
            slow = head;
            while (slow !== fast) {
                slow = slow.next;
                fast = fast.next;
            }
            return slow;
        }
    }
    return null;
}

const T = parseInt(nextLine());
let outputs = [];
for (let t = 0; t < T; ++t) {
    const N = parseInt(nextLine());
    const vals = nextLine().trim().split(/\s+/).map(Number);
    const nodes = new Array(N);
    let head = null, cur = null;
    for (let i = 0; i < N; ++i) {
        const nd = new Node(vals[i]);
        if (!head) head = nd; else cur.next = nd;
        cur = nd;
        nodes[i] = nd;
    }
    const pos = parseInt(nextLine());
    if (pos !== -1) cur.next = nodes[pos];
    const start = detectCycle(head);
    outputs.push(start ? String(start.data) : 'NULL');
}
console.log(outputs.join('\n'));

